sys_ux_client_script.script:
/**
 * @param {params} params
 * @param {api} params.api
 * @param {any} params.event
 * @param {any} params.imports
 * @param {ApiHelpers} params.helpers
 */
function handler({
    api,
    event,
    helpers,
    imports
}) {
    const skipValidation = !!(event && event.payload && event.payload.skipValidation === true);
    const fields = api.state.fields;
    api.setState('fields', fields);
    if (!skipValidation) {
        const nf = imports['x_snc_nf.NextFormUtil']();
        const vr = nf.validateAllFields(api.state.fields);
        if (!vr.allOk) {
            api.setState('canProcess', false);
            return;
        }
    }
    const onLast = api.state.currentScreenNumber === api.state.screenCount;
    api.setState('canProcess', onLast && !api.state.isProcessed);

    api.emit('CTRL_NEXTFORM#PROCESSING_STARTED');

    let nfData = {};

    Object.keys(fields).forEach(function(key) {
        var field = fields[key];
        if (field.isDataField !== false && (!api.context.props.processEditedOnly || (Object.hasOwn(field, 'originalValue') && field.originalValue !== field.value))) {
            nfData[field.name] = {
                name: field.name,
                value: field.value,
                displayValue: field.displayValue
            };
        }
    });

    let payload = {
        nextform_id: api.context.props.nextFormSysId,
        nextform_data: JSON.stringify(nfData)
    };
    let meta;
    if (api.context.props.metadata) {
        meta = {};
        Object.keys(api.context.props.metadata).forEach(key => {
            meta[key] = String(api.context.props.metadata[key]);
        });
        payload.metadata = JSON.stringify(meta);
    }

    api.data.process_nextform_data.execute(payload);
}
